81	    private ParsedParams parseCourseAndMod() {
82	        ParsedParams p = new ParsedParams();
83	
84	        String courseIdRaw = request.getParameter("courseID");
85	        String modRaw = request.getParameter("mod");
86	
87	        // Normal path
88	        if (StringUtils.isNotBlank(courseIdRaw) && StringUtils.isNotBlank(modRaw)) {
89	            p.courseId = courseIdRaw.trim();
90	            p.mod = modRaw.trim();
91	            return p;
92	        }
93	
94	        // Broken URL path: courseID contains "&mod=..."
95	        if (StringUtils.isNotBlank(courseIdRaw) && courseIdRaw.contains("&mod=")) {
96	            String[] parts = courseIdRaw.split("&mod=", 2);
97	            p.courseId = parts[0].trim();
98	            p.mod = (parts.length > 1) ? parts[1].trim() : "";
99	            return p;
100	        }
101	
102	        // Another broken variant: "ESCPXS06248?mod=Classroom" (rare but happens)
103	        if (StringUtils.isNotBlank(courseIdRaw) && courseIdRaw.contains("?mod=")) {
104	            String[] parts = courseIdRaw.split("\\?mod=", 2);
105	            p.courseId = parts[0].trim();
106	            p.mod = (parts.length > 1) ? parts[1].trim() : "";
107	            return p;
108	        }
109	
110	        // Fallback
111	        p.courseId = StringUtils.defaultString(courseIdRaw).trim();
112	        p.mod = StringUtils.defaultString(modRaw).trim();
113	        return p;
114	    }
